// openings.ts — zahájení × varianty × tahy (hlavní obsah)
//
// DŮLEŽITÉ: Každý tah musí být LEGÁLNÍ dle enginu. Build-time validace
// (scripts/validate-openings.ts) projde všechna data a při nelegálním tahu
// nechá spadnout build. Engine navíc křížově kontroluje pole `piece` a
// `captured` proti skutečné pozici na desce. Pokud build hlásí chybu, oprav
// DATA, ne engine.
//
// Notace v české konvenci: J=jezdec, S=střelec, V=věž, D=dáma, K=král,
// rošáda O-O / O-O-O. Bílé tahy "N. tah", černé tahy "N... tah".

import type { MoveDef } from "../lib/chess-engine";

export interface Variation {
  id: string;
  name: string; // český název varianty
  description: string; // 2–4 věty
  moves: MoveDef[];
}

export interface Opening {
  id: string;
  name: string; // český název zahájení
  difficulty: number; // 1–5
  intro: string; // 2–3 věty pro Přehled tab
  history?: string; // volitelný historický kontext
  variations: Variation[];
}

